// src/components/Navbar.jsx
import React, { useState, useEffect } from 'react';
import { Navbar, Nav, Container, NavDropdown, Form, Button, Modal } from 'react-bootstrap';
import { Link, useLocation } from 'react-router-dom';
import { 
  FaHome, FaInfoCircle, FaProjectDiagram, 
  FaEnvelope, FaPhone, FaTimes, FaPaperPlane,
  FaFacebook, FaTwitter, FaInstagram, FaLinkedin,
  FaImages // Make sure this is added here
} from 'react-icons/fa';
import logo from '../assets/logo.png';

const Navigation = () => {
  // ... existing code remains the same ...

  return (
    <>
      <Navbar 
        // ... existing props ...
      >
        <Container fluid className="px-4">
          {/* ... existing brand code ... */}
          
          <Navbar.Collapse id="main-nav">
            <Nav className="ms-auto align-items-lg-center">
              <Nav.Link as={Link} to="/" className="nav-link">
                <FaHome className="me-1" /> Home
              </Nav.Link>
              <Nav.Link as={Link} to="/about" className="nav-link">
                <FaInfoCircle className="me-1" /> About Us
              </Nav.Link>
              
              <NavDropdown 
                // ... existing dropdown ...
              >
                {/* ... dropdown items ... */}
              </NavDropdown>

              {/* Fixed Gallery Link */}
              <Nav.Link as={Link} to="/gallery" className="nav-link gallery-link">
                <FaImages className="me-1" /> Gallery
              </Nav.Link>
              
              <Nav.Link 
                className="nav-link contact-link" 
                onClick={handleContactClick}
              >
                <FaEnvelope className="me-1" /> Contact
              </Nav.Link>
              
              {/* ... existing social icons ... */}
            </Nav>
          </Navbar.Collapse>
        </Container>
      </Navbar>

      {/* ... existing modal ... */}

      {/* Updated Custom CSS */}
      <style jsx>{`
        /* ... existing styles ... */
        
        /* Add specific styles for gallery link */
        .nav-link.gallery-link {
          color: rgba(255, 255, 255, 0.85) !important;
        }
        
        .nav-link.gallery-link:hover {
          color: #88d498 !important;
        }
        
        .nav-link.gallery-link::after {
          content: '';
          position: absolute;
          bottom: 0;
          left: 50%;
          transform: translateX(-50%);
          width: 0;
          height: 2px;
          background: #88d498;
          transition: width 0.3s ease;
        }
        
        .nav-link.gallery-link:hover::after {
          width: 70%;
        }
        
        /* ... rest of existing styles ... */
      `}</style>
    </>
  );
};

export default Navigation;
